import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    min_distance = float('inf')
    best_node = None

    for idx, customer in enumerate(unvisited_customers):
        d = distance(cur_truck_pos, customer)

        # Calculate disutility considering other trucks
        disutility = 0
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                disutility += distance(truck_pos, customer)

        # Total cost considers distance and disutility
        total_cost = d + disutility

        if total_cost < min_distance:
            min_distance = total_cost
            best_node = idx

    # Option to wait if no beneficial move is found
    if min_distance == float('inf'):
        return None

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    num_customers = len(unvisited_customers)
    min_time = float('inf')
    best_node = None

    for i in range(num_customers):
        customer_pos = unvisited_customers[i]
        distance_to_customer = np.linalg.norm(cur_truck_pos - customer_pos)

        # Calculate time considering current positions of other trucks
        time_to_complete = distance_to_customer
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                time_to_wait = np.linalg.norm(truck_pos - customer_pos)
                if time_to_wait < time_to_complete:
                    time_to_complete = time_to_wait

        if time_to_complete < min_time:
            min_time = time_to_complete
            best_node = i

    return best_node

