# Algorithm Description: {Select the next node by evaluating the sum of distances between the current truck position, each customer's position, and the depot, prioritizing minimizing the maximum distance for any truck.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    min_cost = float('inf')
    best_node = None

    for idx, customer in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(cur_truck_pos - customer)
        distance_customer_to_depot = np.linalg.norm(customer - depot_pos)
        total_cost = distance_to_customer + distance_customer_to_depot

        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                distance_other_truck_to_customer = np.linalg.norm(other_truck_pos - customer)
                total_cost = max(total_cost, distance_other_truck_to_customer + distance_customer_to_depot)

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = idx

    return best_node
